import{_ as a,o as s,c as i,a2 as t}from"./chunks/framework.D5wUhsuj.js";const g=JSON.parse('{"title":"Cache & Performance","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/cache-performance.md","filePath":"troubleshooting/cache-performance.md"}'),n={name:"troubleshooting/cache-performance.md"};function o(r,e,l,h,p,c){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="cache-performance" tabindex="-1">Cache &amp; Performance <a class="header-anchor" href="#cache-performance" aria-label="Permalink to &quot;Cache &amp; Performance&quot;">​</a></h1><h2 id="change-not-showing-up" tabindex="-1">&quot;Change not showing up&quot; <a class="header-anchor" href="#change-not-showing-up" aria-label="Permalink to &quot;&quot;Change not showing up&quot;&quot;">​</a></h2><p><span class="ap-pill ap-pill-common">Common — this is the #1 cache support question on every panel that ships page caching</span> You edited a post, changed a menu, or updated something, and the live site still shows the old version.</p><p><strong>First, figure out which kind of change it was — this determines whether it should have auto-purged:</strong></p><p>The Nginx Helper plugin (installed via <code>--install-nginx-helper</code>) purges automatically <strong>only when a post or page is published or updated.</strong> It does <strong>not</strong> auto-purge on:</p><ul><li>menu changes</li><li>widget or Customizer changes</li><li>theme switches or theme-option edits</li><li>plugin install / activate / update</li></ul><p>If your change falls into one of those categories, the old page is still being served correctly <em>by design</em> — it just needs a manual purge:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:purge</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Or from the panel: <strong>Cache</strong> tab → <strong>Purge</strong> next to the domain.</p><p><strong>If it was a post/page edit and it still didn&#39;t purge automatically:</strong></p><ol><li>Confirm the helper plugin is actually installed and active in <code>wp-content/plugins/</code></li><li>Confirm cache is actually enabled for the domain: <code>aidipanel cache:status</code></li><li>Purge manually as a workaround, then check the plugin&#39;s own settings page (WordPress admin → <strong>Settings → Nginx Helper</strong>) for its cache path setting — it needs to match <code>/var/cache/nginx/fastcgi</code> to find and clear the right files</li></ol><p><strong>If purging doesn&#39;t help either:</strong> you&#39;re probably looking at browser or CDN caching rather than server-side cache — try a hard refresh (Ctrl/Cmd+Shift+R) or an incognito window before assuming the server is still stale.</p><h2 id="slow-despite-cache-being-on" tabindex="-1">Slow despite cache being on <a class="header-anchor" href="#slow-despite-cache-being-on" aria-label="Permalink to &quot;Slow despite cache being on&quot;">​</a></h2><p><span class="ap-pill ap-pill-common">Common</span> A few different things can cause this — work through them in order.</p><p><strong>1. Confirm cache is actually enabled and being hit:</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com/</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Look for: X-FastCGI-Cache: HIT</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>If it says <code>MISS</code> every time (not just the first request), something is preventing pages from ever being cached — check the next point.</p><p><strong>2. Check you&#39;re not accidentally always hitting a bypass rule.</strong></p><p>Testing while logged into WordPress, or with a query string in the URL (<code>?utm_source=...</code> from an ad campaign, for example), will <em>always</em> show <code>BYPASS</code> — that&#39;s correct behavior, not a bug. Test from an actual incognito window on a clean URL to get a fair read.</p><p><strong>3. Check overall hit rate, not just one page:</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>A low hit rate (well under 80%) across the whole site suggests either very low-traffic pages that expire before being requested again (<code>inactive=60m</code> default — a page nobody requests within 60 minutes falls out of cache and has to be rebuilt), or a busy site sharing the default zone with other sites and getting evicted early — see <a href="#noisy-neighbour-low-hit-rate">dedicated cache zones</a> below.</p><p><strong>4. Remember what FastCGI Cache does <em>not</em> speed up:</strong></p><p>Page cache only helps anonymous, cacheable requests. If your actual traffic is mostly logged-in users (a membership site, a SaaS dashboard, WooCommerce checkout flows), page cache was never going to help those requests — see <a href="#logged-in-users-and-cache">Logged-in users and cache</a> below, and consider Redis object cache instead for that traffic.</p><p><strong>5. Cache isn&#39;t the only variable.</strong> If hit rate is genuinely high (&gt;80%) and it&#39;s still slow, the bottleneck likely isn&#39;t Nginx/PHP at all — check database query performance, third-party embeds/scripts, or image sizes. A cache hit serves the <em>page shell</em> fast; it doesn&#39;t fix a 5MB hero image or a slow third-party analytics script loading in the browser.</p><h2 id="logged-in-users-and-cache" tabindex="-1">Logged-in users and cache <a class="header-anchor" href="#logged-in-users-and-cache" aria-label="Permalink to &quot;Logged-in users and cache&quot;">​</a></h2><p><span class="ap-pill ap-pill-rare">Expected behavior, not a bug</span> If logged-in users (WordPress admins, WooCommerce customers with items in cart) report seeing something stale, that&#39;s actually the <em>opposite</em> of a cache problem — logged-in and cart-bearing traffic is explicitly excluded from cache by the default rules, specifically so no one is ever served a cached response meant for someone else.</p><p>If a logged-in user is seeing outdated content, the cause is almost always something else entirely: browser caching, a CDN in front of AidiPanel (Cloudflare, etc.) caching independently at its own layer, or an actual application-level issue unrelated to FastCGI Cache. Confirm with:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sI</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;wordpress_logged_in_test=1&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> X-FastCGI-Cache</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Should always show: BYPASS</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>If this shows <code>HIT</code> instead of <code>BYPASS</code>, that is a real problem worth stopping and investigating immediately — see <a href="/docs/tutorials/multi-php-woocommerce-cache#what-to-verify-after-enabling">Multi-PHP &amp; WooCommerce Cache → What to verify after enabling</a>.</p><h2 id="noisy-neighbour-low-hit-rate-on-a-busy-site" tabindex="-1">Noisy neighbour (low hit rate on a busy site) <a class="header-anchor" href="#noisy-neighbour-low-hit-rate-on-a-busy-site" aria-label="Permalink to &quot;Noisy neighbour (low hit rate on a busy site)&quot;">​</a></h2><p><span class="ap-pill ap-pill-rare">Occasional, on multi-site boxes</span> By default every site shares one FastCGI cache zone. Cache <em>keys</em> are host-scoped so entries from different domains never collide or leak into each other — but the <em>eviction budget</em> is shared, so a very high-traffic site can push a quieter site&#39;s cached pages out sooner than its own TTL would otherwise allow.</p><p>If <code>cache:status</code> shows a specific busy domain with a lower hit rate than expected, give it a dedicated zone:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:zone</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --action</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 64m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-size</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 5g</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:zone</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --action</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Full explanation: <a href="/docs/guide/fastcgi-cache#dedicated-cache-zones-noisy-neighbour">FastCGI Cache → Dedicated cache zones</a>. Most sites never need this — reach for it only after confirming via <code>cache:status</code> that eviction is actually the problem, not one of the other causes above.</p><h2 id="high-server-load-in-general-not-cache-specific" tabindex="-1">High server load in general (not cache-specific) <a class="header-anchor" href="#high-server-load-in-general-not-cache-specific" aria-label="Permalink to &quot;High server load in general (not cache-specific)&quot;">​</a></h2><p>If the whole server feels sluggish rather than one particular site:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># What&#39;s actually consuming resources right now</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> system:info</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">top</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Common causes on a shared multi-site VPS: one site getting a traffic spike and its PHP-FPM pool consuming most of the CPU/RAM (isolated per-site pools mean this <em>shouldn&#39;t</em> crash other sites, but it can still slow the box overall if RAM is genuinely exhausted), a runaway cron job or import script, or simply being under-provisioned for the number/size of sites hosted — compare current usage against the <a href="/docs/guide/installation#requirements">recommended specs</a> for a sanity check.</p>`,39)])])}const u=a(n,[["render",o]]);export{g as __pageData,u as default};
